class Data:
    START = (
        "🌟 Welcome {0}! 🌟\n\n"
    )
# Define the start command handler
@bot.on_message(filters.command("start"))
async def start(client: Client, msg: Message):
    user = await client.get_me()
    mention = user.mention
    caption = f"🌟 Welcome {msg.from_user.mention} ! 🌟"
    start_message = await client.send_photo(
        chat_id=msg.chat.id,
        photo="https://envs.sh/0oy.jpg",
        caption=caption
    )

    await asyncio.sleep(1)
    await start_message.edit_text(
        Data.START.format(msg.from_user.mention) +
        "Initializing Uploader bot... 🤖\n\n"
        "Progress: [⬜⬜⬜⬜⬜⬜⬜⬜⬜] 0%\n\n"
    )

    await asyncio.sleep(1)
    await start_message.edit_text(
        Data.START.format(msg.from_user.mention) +
        "Loading features... ⏳\n\n"
        "Progress: [🟥🟥🟥⬜⬜⬜⬜⬜⬜] 25%\n\n"
    )
    
    await asyncio.sleep(1)
    await start_message.edit_text(
        Data.START.format(msg.from_user.mention) +
        "This may take a moment, sit back and relax! 😊\n\n"
        "Progress: [🟧🟧🟧🟧🟧⬜⬜⬜⬜] 50%\n\n"
    )

    await asyncio.sleep(1)
    await start_message.edit_text(
        Data.START.format(msg.from_user.mention) +
        "Checking subscription status... 🔍\n\n"
        "Progress: [🟨🟨🟨🟨🟨🟨🟨⬜⬜] 75%\n\n"
    )

    await asyncio.sleep(1)
    if msg.from_user.id in auth_data:
        user = await client.get_me()
        mention = user.mention
        ist = pytz.timezone('Asia/Kolkata')
        now = datetime.now(ist)
        start_datetime_str = "01-10-2024 00:00:00"
        end_datetime_str = "31-12-2024 23:59:59"
        start = datetime.strptime(start_datetime_str, "%d-%m-%Y  %H:%M:%S")
        end = datetime.strptime(end_datetime_str, "%d-%m-%Y  %H:%M:%S")
        start_ist = ist.localize(start)
        end_ist = ist.localize(end)      # End datetime in IST
        time_diff = end_ist - now
        subs_day = end_ist - start_ist
        days1 = subs_day.days
        days = time_diff.days
        hours, remainder = divmod(time_diff.seconds, 3600)
        minutes, seconds = divmod(remainder, 60)
        caption =  f"🌟 Welcome **{msg.from_user.mention}** !\n\n**Great! You are a Premium Member! 🌟**\n\n**⏰ Join Datetime :** {start}\n\n**📅 Subscription Days :** {days1} Days\n\n**⏰ Expiration DateTime :** {end}\n\n**⌛Remaining Time :** {days} Days, {hours} Hours, {minutes} Minutes, and {seconds} Seconds\n\n➠ 𝐌𝐚𝐝𝐞 𝐁𝐲: **[『 𝗠ᴇɢᴀᴛʀᴏɴ 🧑‍💻』](tg://user?id=7535195022)⁬**\n\nPress **Help** Button To Use Me Properly"
        keyboard = InlineKeyboardMarkup(
          [
            [InlineKeyboardButton("Help", callback_data="help_command")]
          ]
        )
        await start_message.edit_media(
          InputMediaPhoto(
            caption=caption,
            media="https://envs.sh/qho.jpg"
          ),
          reply_markup=keyboard
        )
    else:
        await asyncio.sleep(1)
        user = await client.get_me()
        mention = user.mention
        caption = f"🌟 Welcome **{msg.from_user.mention}** !\n\n**You are currently using the free version.** 🆓\n\nI'm here to make your life easier by downloading videos from your **.txt** file 📄 and uploading them directly to Telegram!\n\n**Want to get started? Press /id**\n\n💬 Contact : **[『 𝗠ᴇɢᴀᴛʀᴏɴ 🧑‍💻』](tg://user?id=7535195022)** to Get The Subscription 🎫 and unlock the full potential of your new bot! 🔓"
        keyboard = InlineKeyboardMarkup(
          [
            [InlineKeyboardButton("💎 Features", callback_data="feature_command"), InlineKeyboardButton("🎫 plans", callback_data="upgrade_command")]
          ]
        )
        await start_message.edit_media(
          InputMediaPhoto(
            caption=caption,
            media="https://envs.sh/qQY.jpg"
          ),
          reply_markup=keyboard
        )

